supabase.body:
export const supabase = createClient(url, anonKey, {
    auth: {
        // Keep the session in localStorage and refresh it automatically. This is
        // per-browser (each browser logs in once via magic link) — the *data*
        // is what now lives server-side and follows the user everywhere.
        persistSession: true,
        autoRefreshToken: true,
        // Parse the magic-link token out of the URL on return, then clean it up.
        detectSessionInUrl: true,
    },
})

traceStore.body:
export function traceStore(
  store: { subscribe: (l: (n: unknown, p: unknown) => void) => () => void },
  name: string,
): void {
  if (!DEV || !store?.subscribe) return;
  const unsub = store.subscribe((next, prev) => {
    const changes: Leaf[] = [];
    diff("", prev, next, changes);
    if (changes.length === 0) return;
    push({ seq: seq++, t: now(), kind: "change", store: name, changes, by: callsite() });
  });
  unsubs.push(unsub);
}

