workspace__pointerBridge.body:
export function useWorkspacePointerBridge(forward: ForwardMouse): void {
    useEffect(() => {
        //20th June
        const onMouseMove = (e: MouseEvent) => forward(mouseEventDataFrom(e), "workspace-area-mouse-move")
        const onMouseUp   = (e: MouseEvent) => forward(mouseEventDataFrom(e), "workspace-area-mouse-up")

        document.addEventListener('mousemove', onMouseMove)
        document.addEventListener('mouseup',   onMouseUp)
        return () => {
            document.removeEventListener('mousemove', onMouseMove)
            document.removeEventListener('mouseup',   onMouseUp)
        }
    }, [forward])
}

resolveCollisions.body:
export function resolveCollisions(items: LayoutItem[], movedBlockId: string): LayoutItem[] {
    const sorted = items
        .map(i => ({ ...i }))
        .sort((a, b) => {
            if (a.y !== b.y) return a.y - b.y
            if (a.blockId === movedBlockId) return -1
            if (b.blockId === movedBlockId) return 1
            return 0
        })

    for (let i = 1; i < sorted.length; i++) {
        const minY = sorted[i - 1].y + sorted[i - 1].h
        if (sorted[i].y < minY) {
            sorted[i] = { ...sorted[i], y: minY }
        }
    }

    return sorted
}

layout__resolve.body:
export function resolveFileCollisions(
    fileId: string,
    content: string[],
    layouts: LayoutDataSet,
    movedBlockId: string,
): LayoutDataSet {
    const resolved = resolveCollisions(measuredItemsForFile(fileId, content, layouts), movedBlockId)
    const merged: LayoutDataSet = { ...layouts }
    for (const item of resolved) merged[layoutKey(fileId, item.blockId)] = item
    return merged
}

layout__orderBy.body:
export function orderByPosition(
    blockIds: string[],
    fileId: string,
    layouts: LayoutDataSet,
    fallback: number,
): string[] {
    return [...blockIds].sort((idA, idB) => {
        const a = layouts[layoutKey(fileId, idA)]
        const b = layouts[layoutKey(fileId, idB)]
        const ay = a?.y ?? fallback, ax = a?.x ?? fallback
        const by = b?.y ?? fallback, bx = b?.x ?? fallback
        return (ay - by) || (ax - bx)
    })
}

