drag__arm.body:
private armDrag = (mouseData: MouseEventData): void => {
    const target = document.elementFromPoint(
      mouseData.clientX,
      mouseData.clientY,
    );
    const el = target?.closest(".drag-container") as HTMLElement | null;
    if (!el) return;

    this.activeEl = el;
    this.activeId = el.id;
    this.startClient = { x: mouseData.clientX, y: mouseData.clientY };
    this.isArmed = true;
    this.isActive = false;
  };

drag__activate.body:
private activateDrag = (mouseData: MouseEventData): void => {
    if (!this.activeEl) return;
    const rect = this.activeEl.getBoundingClientRect();

    this.mouseOffset = {
      x: mouseData.clientX - rect.left,
      y: mouseData.clientY - rect.top,
    };

    if (this.workspaceEl) {
      const ws = this.workspaceEl.getBoundingClientRect();
      this.lastLocal = {
        x: rect.left - ws.left + this.workspaceEl.scrollLeft,
        y: rect.top - ws.top + this.workspaceEl.scrollTop,
      };
    } else {
      this.lastLocal = { x: rect.left, y: rect.top };
    }

    this.isActive = true;
  };

drag__move.body:
private moveActive = (mouseData: MouseEventData): void => {
    if (!this.isArmed || !this.activeEl) return;

    if (!this.isActive) {
      const dx = mouseData.clientX - this.startClient.x;
      const dy = mouseData.clientY - this.startClient.y;
      if (Math.hypot(dx, dy) < DRAG_THRESHOLD_PX) return; // still a click
      this.activateDrag(mouseData);
    }

    if (!this.workspaceEl) return;
    const ws = this.workspaceEl.getBoundingClientRect();

    // .drag-container is absolute inside the relative, SCROLLABLE workspace.
    // style.top is content-space, so convert the viewport cursor to
    // content-space: subtract ws.top, add scrollTop.
    let localX =
      mouseData.clientX -
      this.mouseOffset.x -
      ws.left +
      this.workspaceEl.scrollLeft;
    let localY =
      mouseData.clientY -
      this.mouseOffset.y -
      ws.top +
      this.workspaceEl.scrollTop;

    // Clamp to the scrollable content bounds (not just the visible window).
    localX = Math.max(
      0,
      Math.min(
        localX,
        this.workspaceEl.scrollWidth - this.activeEl.offsetWidth,
      ),
    );
    localY = Math.max(
      0,
      Math.min(
        localY,
        this.workspaceEl.scrollHeight - this.activeEl.offsetHeight,
      ),
    );

    // X locked → leave style.left to CSS (PAGE_X), keep seeded x in lastLocal.
    if (!this.lockX) {
      this.activeEl.style.left = `${localX}px`;
    } else {
      localX = this.lastLocal.x;
    }
    this.activeEl.style.top = `${localY}px`;

    this.lastLocal = { x: localX, y: localY };
  };

drag__end_.body:
private endDrag = (shape: DocShape): DocShape => {
    if (!this.isArmed || !this.activeId) {
      this.cleanup();
      return shape;
    }

    const movedId = this.activeId;
    const finalLocal = this.lastLocal;
    const wasActive = this.isActive;

    this.cleanup();

    if (!wasActive || !shape.file) return shape;
    return this.applyPlacement(shape, shape.file.id, movedId, finalLocal);
  };

drag__apply.body:
private applyPlacement = (
    shape: DocShape,
    fileId: string,
    blockId: string,
    finalLocal: Position,
  ): DocShape => {
    const key = layoutKey(fileId, blockId);
    const existing = shape.layoutData[key];
    if (!existing) return shape;
    const layoutData = {
      ...shape.layoutData,
      [key]: { ...existing, x: finalLocal.x, y: finalLocal.y },
    };
    return { ...shape, layoutData };
  };

drag__cleanup.body:
private cleanup = (): void => {
    this.activeEl = null;
    this.activeId = null;
    this.isArmed = false;
    this.isActive = false;
    this.startClient = { x: 0, y: 0 };
    this.mouseOffset = { x: 0, y: 0 };
    this.lastLocal = { x: 0, y: 0 };
  };

panelChrome.body:
export default function Panel({ cn, panelData, open, onAddFile, onInsertBlock }: PanelProps) {

    const setActiveFile = useWorkspaceStore(s => s.setActiveFile)

    const tileNames: string[] = panelData.map(panel => panel.tileName)

    // First tile (Files) is selected by default — this is the home view on load.
    const [selectedTile, setSelectedTile] = useState<string>(tileNames[0])
    const [selectedBodyItem, setSelectedBodyItem] = useState<string>("")

    const handleTileClicked = (tileName: string) => setSelectedTile(tileName)

    const selectedPanelTile = panelData.find(item => item.tileName === selectedTile)
    if (!selectedPanelTile) return null

    // The list of body items rendered under the selected tile (file names or block names).
    const panelBody: string[] = selectedPanelTile.type === "files"
        ? selectedPanelTile.panelBody.map(f => f.fileName)
        : selectedPanelTile.panelBody.map(b => b.block)

    // Body click — activates a file (Files tile) or inserts a block (Blocks tile).
    const handleBodyItemClick = (name: string) => {
        setSelectedBodyItem(name)
        if (selectedPanelTile.type === "files") {
            const file: FileData | undefined = selectedPanelTile.panelBody.find(f => f.fileName === name)
            if (file) setActiveFile(file)
        } else if (selectedPanelTile.type === "blocks") {
            const spec = selectedPanelTile.panelBody.find(b => b.block === name)
            if (spec && onInsertBlock) onInsertBlock(spec)
        }
    }

    return (
        <div className={`panel ${cn} panel-open-${open}`}>
            <PanelHeader
                cn={cn}
                panelOpen={open}
                tileNames={tileNames}
                handleTileClicked={handleTileClicked}
                selectedTile={selectedTile}
            />
            {open && selectedPanelTile.type === "files" && onAddFile && (
                <button
                    type="button"
                    className={`${cn} panel-add-file`}
                    onClick={onAddFile}
                >
                    <span className="panel-add-file-icon" aria-hidden="true">+</span>
                    New file
                </button>
            )}
            <PanelBody
                cn={cn}
                panelSubItem={panelBody}
                selectedBodyItem={selectedBodyItem}
                handleBodyItemClick={handleBodyItemClick}
            />
        </div>
    )
}

PanelBody.body:
export default function PanelBody({
